import{_ as a,o as n,c as s,ag as i}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Personnalisation PDF","description":"","frontmatter":{},"headers":[],"relativePath":"fr/settings/pdf.md","filePath":"fr/settings/pdf.md"}'),o={name:"fr/settings/pdf.md"};function t(r,e,l,u,d,c){return n(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="personnalisation-pdf" tabindex="-1">Personnalisation PDF <a class="header-anchor" href="#personnalisation-pdf" aria-label="Permalink to &quot;Personnalisation PDF&quot;">​</a></h1><p>Personnalisez l&#39;apparence de vos PDF de factures, devis et avoirs pour correspondre a votre marque.</p><h2 id="editeur-pdf" tabindex="-1">Editeur PDF <a class="header-anchor" href="#editeur-pdf" aria-label="Permalink to &quot;Editeur PDF&quot;">​</a></h2><p>L&#39;editeur PDF visuel vous permet de personnaliser la mise en page de vos documents avec un apercu en direct.</p><h3 id="acceder-a-l-editeur" tabindex="-1">Acceder a l&#39;editeur <a class="header-anchor" href="#acceder-a-l-editeur" aria-label="Permalink to &quot;Acceder a l&#39;editeur&quot;">​</a></h3><p>Allez dans <strong>Entreprise &gt; Editeur PDF</strong> ou accedez-y depuis Entreprise &gt; Image de marque.</p><h3 id="options-de-personnalisation" tabindex="-1">Options de personnalisation <a class="header-anchor" href="#options-de-personnalisation" aria-label="Permalink to &quot;Options de personnalisation&quot;">​</a></h3><h4 id="mise-en-page" tabindex="-1">Mise en page <a class="header-anchor" href="#mise-en-page" aria-label="Permalink to &quot;Mise en page&quot;">​</a></h4><ul><li><strong>Position et taille du logo</strong> -- Placez votre logo la ou il rend le mieux</li><li><strong>Placement des informations de l&#39;entreprise</strong> -- Positionnez vos coordonnees professionnelles</li><li><strong>Placement des informations du client</strong> -- Ou apparaissent les coordonnees du client</li><li><strong>Tableau des lignes</strong> -- Largeurs de colonnes et alignement</li></ul><h4 id="contenu" tabindex="-1">Contenu <a class="header-anchor" href="#contenu" aria-label="Permalink to &quot;Contenu&quot;">​</a></h4><p>Choisissez quels champs afficher ou masquer :</p><ul><li>Numero de TVA de l&#39;entreprise</li><li>Numero d&#39;immatriculation de l&#39;entreprise</li><li>IBAN / coordonnees bancaires</li><li>Conditions de paiement</li><li>Section notes</li><li>Texte de pied de page</li></ul><h4 id="style" tabindex="-1">Style <a class="header-anchor" href="#style" aria-label="Permalink to &quot;Style&quot;">​</a></h4><ul><li><strong>Police</strong> -- Choisissez parmi les polices disponibles</li><li><strong>Taille de police</strong> -- Ajustez la taille du texte</li><li><strong>Couleur d&#39;accentuation</strong> -- Votre couleur de marque pour les en-tetes et les accents</li><li><strong>Interligne</strong> -- Ajustez la densite du document</li></ul><h3 id="apercu" tabindex="-1">Apercu <a class="header-anchor" href="#apercu" aria-label="Permalink to &quot;Apercu&quot;">​</a></h3><p>L&#39;editeur affiche un apercu en temps reel avec des donnees exemples. Vous pouvez egalement generer un <strong>PDF exemple</strong> pour voir exactement a quoi ressemblera une facture imprimee.</p><h2 id="types-de-documents" tabindex="-1">Types de documents <a class="header-anchor" href="#types-de-documents" aria-label="Permalink to &quot;Types de documents&quot;">​</a></h2><p>Les parametres PDF s&#39;appliquent a tous les documents generes :</p><ul><li><strong>Factures</strong> -- Documents de facturation standard</li><li><strong>Devis</strong> -- Documents de devis</li><li><strong>Avoirs</strong> -- Documents de remboursement/ajustement</li><li><strong>Rappels</strong> -- Documents de rappel de paiement</li></ul><h2 id="prise-en-charge-linguistique" tabindex="-1">Prise en charge linguistique <a class="header-anchor" href="#prise-en-charge-linguistique" aria-label="Permalink to &quot;Prise en charge linguistique&quot;">​</a></h2><p>Les PDF sont generes dans la langue de la facture. Si vous envoyez une facture en allemand, les libelles du PDF (comme &quot;Facture&quot;, &quot;Date d&#39;echeance&quot;, &quot;Total&quot;) apparaissent en allemand.</p><p>Langues PDF prises en charge : anglais, neerlandais, allemand, francais.</p><h2 id="exigences-pour-le-logo" tabindex="-1">Exigences pour le logo <a class="header-anchor" href="#exigences-pour-le-logo" aria-label="Permalink to &quot;Exigences pour le logo&quot;">​</a></h2><p>Pour de meilleurs resultats :</p><ul><li><strong>Format :</strong> PNG avec fond transparent (recommande), JPG ou SVG</li><li><strong>Resolution :</strong> Au moins 300px de large</li><li><strong>Ratio d&#39;aspect :</strong> Les logos paysage ou carres fonctionnent le mieux</li><li><strong>Taille du fichier :</strong> Moins de 2 Mo</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Les logos SVG sont automatiquement convertis en PNG pour la compatibilite e-mail.</p></div><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Generez un PDF exemple apres chaque modification pour verifier la mise en page</li><li>Utilisez la couleur d&#39;accentuation de votre marque pour un aspect professionnel</li><li>Gardez la mise en page epuree -- ne surchargez pas le PDF avec trop d&#39;informations</li><li>Testez avec une vraie facture (a vous-meme) avant d&#39;envoyer aux clients</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>La personnalisation avancee du PDF necessite le plan <strong>Pro</strong> ou superieur.</p></div>',29)])])}const g=a(o,[["render",t]]);export{m as __pageData,g as default};
